html: <!DOCTYPE html>
<html lang="en" dir="ltr">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Floating Elements</title>
    <link rel="stylesheet" href="https://cdn.tailwindcss.com">
</head>
<body>
    <div class="h-screen w-screen flex justify-center items-center relative">
        <img src="https://picsum.photos/200/300" alt="Background Image">
        <div id="floating-text" class="bg-gray-800 text-white absolute top-0 left-0 p-4 text-lg font-bold shadow-lg">
            Floating Text
        </div>
    </div>
    <script src="script.js"></script>
</body>
</html>
css: body {
    /* Add global styles here */
}

#floating-text {
    /* Add styles for the floating text here */
    animation: float-animation 10s infinite linear;
}

@keyframes float-animation {
    0% {
        top: 0;
        left: 0;
    }
    25% {
        top: 50%;
        left: 50%;
    }
    50% {
        top: 100%;
        left: 0;
    }
    75% {
        top: 100%;
        left: 100%;
    }
    100% {
        top: 0;
        left: 100%;
    }
}

js: document.addEventListener('DOMContentLoaded', function () {
    const floatingText = document.getElementById('floating-text');
    floatingText.style.transform = 'translate(0, 0)';
    const intervalId = setInterval(function () {
        const x = Math.floor(Math.random() * 100);
        const y = Math.floor(Math.random() * 100);
        floatingText.style.top = `${y}%`;
        floatingText.style.left = `${x}%`;
        floatingText.style.transform = `translate(${x}%, ${y}%)`;
    }, 2000);
    setTimeout(function () {
        clearInterval(intervalId);
        floatingText.style.display = 'none';
    }, 5000);
});
